// Helper function to get full icon data
export const getIcon = (index: number) => {
  const icon = icons[index];
  return {
    category: categories[icon.c],
    name: icon.n,
    className: `icon54-l_${categories[icon.c]}-${icon.n}`,
  };
};

// Helper function to get icons by category
export const getIconsByCategory = (categoryName: string) => {
  const categoryId = categories.indexOf(categoryName);
  if (categoryId === -1) return [];
  return icons
    .map((icon, index) => ({ ...icon, index }))
    .filter((icon) => icon.c === categoryId)
    .map((icon) => ({
      category: categoryName,
      name: icon.n,
      className: `icon54-l_${categoryName}-${icon.n}`,
      index: icon.index,
    }));
};

export default icons;
